import json
import re

files = [
    locals()['var_function-call-14922489355261499953'],
    locals()['var_function-call-5879761063621689848']
]

targets = [
    "Goal-setting And Achievement In Activity Tracking Apps: A Case Study Of MyFitnessPal.txt",
    "Closing the Gap: Supporting Patients' Transition to Self-Management After Hospitalization.txt"
]

results = {}
for file_path in files:
    with open(file_path, 'r') as f:
        docs = json.load(f)
    for doc in docs:
        if doc['filename'] in targets:
            text = doc['text']
            # Search for CHI in first 3000 chars
            header = text[:3000]
            if re.search(r"CHI\s*20\d{2}", header, re.IGNORECASE) or re.search(r"CHI\s*'\d{2}", header, re.IGNORECASE):
                results[doc['filename']] = "CHI"
            else:
                results[doc['filename']] = "Not CHI"

print("__RESULT__:")
print(json.dumps(results))

